class Solution:
    def countKReducibleNumbers(self, s: str, k: int) -> int:
        MOD = 10**9 + 7
        n = len(s)
        target = int(s, 2)

        memo = {}

        def count_set_bits(num):
            count = 0
            while num:
                count += num & 1
                num >>= 1
            return count

        def is_k_reducible(num, k):
            for _ in range(k):
                num = count_set_bits(num)
                if num == 1:
                    return True
            return False

        def dp(i, num, k):
            if k < 0:
                return 0
            if i == n:
                return 1 if num < target and is_k_reducible(num, k) else 0
            if (i, num, k) in memo:
                return memo[(i, num, k)]

            res = 0
            if s[i] == '1':
                res += dp(i + 1, num << 1, k)
                res += dp(i + 1, (num << 1) + 1, k - (bin(num).count('1') + 1 == 1))
            else:
                res += dp(i + 1, num << 1, k)

            res %= MOD
            memo[(i, num, k)] = res
            return res

        return dp(0, 0, k)

